// Dagelijkse rotatie van (sector, city) over een vaste tabel.
// 5 Tier-1 sectoren × 8 hoofdsteden = 40 combinaties,
// ~8 weken voordat we terug bij dezelfde combo zijn.
// Jitter op city-index voorkomt dat we altijd dezelfde stad per weekdag krijgen.

const SECTORS = ['installateurs', 'vastgoed', 'medisch', 'dakwerken', 'bouw'];
const CITIES = ['Gent', 'Antwerpen', 'Mechelen', 'Leuven', 'Hasselt', 'Brugge', 'Kortrijk', 'Aalst'];

const now = new Date();
const start = new Date(Date.UTC(now.getUTCFullYear(), 0, 0));
const dayOfYear = Math.floor((now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

const sector = SECTORS[dayOfYear % SECTORS.length];
const city = CITIES[Math.floor(dayOfYear / SECTORS.length) % CITIES.length];

return [{ json: { sector, city, limit: 50, dayOfYear } }];
